INSERT INTO transfer_targets VALUES(10,'2026-summer','Modou Kéba Cissé','시세',1944705,'LASK → Aston Villa','CB','RCB','CONFIRMED','00200001420237413X9814X84',60.89999999999999858,31.19999999999999929,6,6.769999999999999574,'cb_defender','Balanced','cb_bpd','Aggressive',0.8900000000000000133,'CONFIRMED incoming: pre-contract signed summer 2025, joins for 2026/27 after a season at LASK. Measured: right-of-centre CB (60.9,31.2), Ball-Playing Defender/Aggressive fit 0.89 — same fit family as Konsa (0.88). Natural RCB cover/heir; Austrian Bundesliga level caveat. [2026-07-15 재확인] RotoWire: 공식 합류 확인(사전계약, LASK에서 2026년 여름 발효).','https://readastonvilla.com/2026/05/14/modou-keba-cisse-the-future-aston-villa-player-who-is-shining-in-austria/ ; SofaScore API player 1944705 (2026-07-02)','CONFIRMED signing; measured from LASK (league-strength caveat). / 2026-07-15: 공식 완료 확인 — CONFIRMED 유지.','시세');
INSERT INTO transfer_targets VALUES(11,'2026-summer','Zion Suzuki','스즈키',905351,'Parma','GK','GK','MEDIUM-HIGH','0000000000000000010001X20',50.29999999999999716,7.299999999999999823,6,7.129999999999999894,'gk_sweeper','Balanced','gk_goalkeeper','Defend',0.969999999999999974,'UPGRADED from USER WATCHLIST (2026-07-02 evening watch): ROMANO (tier-1) — Villa scouting Suzuki for months; he is on a 3-GK shortlist (with Trafford of Man City; 3rd unnamed, possibly Trubin) for the Martínez succession, as Martínez nears Juventus. Parma ask ~€30m (£26m); Leeds "battle" reported; Bayern/Inter/Napoli/ManU watching. Measured: goal-line GK (50.3,7.3), fit gk_goalkeeper/Defend 0.97; best sampled GK avg rating (7.13 at Parma). Sweeper/build-up retraining question stands, as with Trubin. [2026-07-15 재확인] 리세가 1순위이며 수즈키는 대안, 아직 구단간 컨택 전 에이전트 대상 탐색 단계.','https://www.teamtalk.com/aston-villa/villa-scouting-parma-keeper-zion-suzuki-three-man-shortlist-replace-emiliano-martinez ; https://sports.yahoo.com/articles/aston-villa-want-parma-goalkeeper-185000163.html ; SofaScore API player 905351 (2026-07-02)','MEDIUM-HIGH — [2026-07-14 재확인] 마르티네스 기사에서 "빌라 1순위 대체는 리세르, 스즈키는 대안"으로 우선순위 하락 확인. 뉴캐슬이 협상 개시(negotiations)로 경쟁 심화. tier-1(Romano) 관심 보도는 유지. 등급 유지. / 2026-07-15 재확인: 리세르가 1옵션, 수즈키는 대안으로 순위 하락 지속.','스즈키');
INSERT INTO transfer_targets VALUES(13,'2026-summer','Alysson','알리송',1631879,'Aston Villa (2026-01, Grêmio €10M)','RW','RM','OWNED','001640014X000380003600011',83.20000000000000284,59.70000000000000284,6,6.75,'wm_winger','Attack','wm_insidefwd','Balanced',0.8499999999999999778,'ALREADY OWNED: joined from Grêmio for €10M in January 2026; young (2006) right winger not yet in the analysis roster. Measured: genuine wide-right (83.2,59.7) — the squad''s only natural touchline RW; fit Inside Forward/Balanced 0.85. Prescription Winger/Attack to use his width+pace profile distinct from McGinn/Bowen half-space types.','https://www.fotmob.com/teams/10252/transfers/aston-villa ; SofaScore API player 1631879 (2026-07-02)','OWNED; measured mixes Grêmio+Villa minutes (sample caveat).',NULL);
INSERT INTO transfer_targets VALUES(16,'2026-summer','Guillaume Restes','레스테스',1154630,'Toulouse','GK','GK','HIGH','0000000000000000210002X20',47.60000000000000142,11.80000000000000071,6,6.919999999999999929,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.969999999999999974,'Villa have held talks with his representatives — the young (2005) GK track alongside Trubin. Measured: goal-line (47.6,11.8), 6.92 avg at Toulouse. Same sweeper-retraining question as all GK targets. [2026-07-03 watch: still cited as serious No.1 option if Martínez leaves; verbal-agreement claim remains tier-2/3 (TeamTalk) with no tier-1 confirmation. Ipswich/Napoli also in. Grade unchanged.] [갱신 2026-07-04] 구두합의 도달 보도(TeamTalk/SportsMole/Sportingpedia) — 단, 마르티네스의 유벤투스 이적 성사가 선행조건. [2026-07-09 watch: TeamTalt/CaughtOffside — 구두합의 도달(€18-20m), 마르티네스 유벤투스 이적 조건부이나 그쪽도 개인조건 합의 단계로 진전 → MEDIUM-HIGH에서 HIGH 상향.] [2026-07-15 재확인] Fabrizio Romano(1티어): 툴루즈 요구가 €20m 확인. Athletic Jacob Tanswell(1티어): 대리인측과 회담 진행 확인.','https://www.skysports.com/football/live-blog/11677/13025491 ; SofaScore API player 1154630 (2026-07-02)','HIGH — [2026-07-14 재확인] 나폴리·입스위치·웨스트햄·뉴캐슬까지 4파전으로 경쟁 확대됐으나 구두합의(TeamTalk·TheHardTackle) 보도는 유지. 등급 유지. / 2026-07-15 재확인: Romano(1티어) 요구가 €20m 확인, Athletic Tanswell(1티어) 대리인 회담 확인, 등급 유지.','레스테스');
INSERT INTO transfer_targets VALUES(18,'2026-summer','Anis Hadj Moussa','하지 무사',1218066,'Feyenoord','RW','RM','HIGH','312691114X000140002400001',76.90000000000000569,69.29999999999999716,6,7.549999999999999823,'wm_winger','Attack','wm_insidefwd','Attack',0.9200000000000000399,'ADVANCE TALKS (Villa vs Newcastle); player prioritising a PL move for 26/27, Feyenoord ask ~€35m. Measured: high-and-wide right winger (76.9,69.3), Inside Forward/Attack fit 0.92 — the HIGHEST RM-slot fit sampled (Bowen 0.88) AND the highest avg rating of all targets (7.55). Eredivisie level caveat. [2026-07-03 watch: talks well underway with both Villa & Newcastle, expected to accelerate; Newcastle edge — Villa CL squad-registration restriction (UEFA fine) may hamper. Feyenoord ~€35m. Grade unchanged.] [2026-07-09 watch: TransferFeed/Yahoo — 빌라·뉴캐슬이 "most advanced in discussions" 공식 표현으로 보도, 선수 본인도 PL 선호 재확인. MEDIUM-HIGH에서 HIGH 상향.] [2026-07-15 재확인] Sacha Tavolieri(2티어급): "advanced talks" 보도 재확인, 대리인이 빌라·뉴캐슬 지목. 페예노르트 €35m 고수.','https://thehardtackle.com/transfer-news/2026/06/30/aston-villa-newcastle-united-advance-talks-to-sign-anis-hadj-moussa/ ; SofaScore API player 1218066 (2026-07-02)','HIGH — 다수 매체가 "most advanced discussions" 표현 사용, 선수 PL 선호 명확. / 2026-07-15 재확인: "advanced talks" 재확인(Tavolieri), 등급 유지.','하지무사');
