INSERT INTO transfer_targets VALUES(30,'2026-summer','Tammy Abraham','타미 아브라함',610766,'Aston Villa','ST','ST','OWNED','01855255648X8415422010200',47.39999999999999858,59.0,4,6.849999999999999645,'st_target','Attack','st_false9','Attack',0.5200000000000000177,'ALREADY OWNED: 2026-01-27 베식타슈에서 ~£18m로 빌라 복귀(1일 만에 재이적), 그 시즌 유로파리그 우승. 여름 루머 대상이 아니라 보유 선수(알리송과 동일 케이스) — 사용자 요청으로 OWNED ST 옵션으로 편입. 실측(반시즌 통틀어 45분+ 4경기 전부 ST): 중앙-약간좌측·깊은 풋프린트 (47.4,59.0), 평균 6.85. 최근접 st_false9/Attack 0.52 — 왓킨스(st_advanced 자기커널)·기라시 0.80·브로베이 0.75·파르도 0.87보다 명확히 낮음. 처방은 타깃/홀드업 아키타입 반영 st_target/Attack. 표본 캐비앳: 왓킨스의 로테이션 백업이라 45분+ 경기가 반시즌 4경기뿐이고 전부 교체 출전(추격 상황 드롭) → 깊은 편향된 풋프린트, 선발 표본 아님.','https://www.avfc.co.uk/news/2026/january/27/signing-aston-villa-confirm-tammy-abraham-signing/ ; SofaScore API player 610766 (2026-07-03)','OWNED — 이적 루머 아님(2026-01 합류확정 보유선수). 측정 신뢰 MEDIUM(표본 4경기·전부 교체출전·맥락 편향, 45분+ 6경기 미달).',NULL);
INSERT INTO transfer_targets VALUES(33,'2026-summer','Lloyd Kelly','로이드 켈리',865167,'Juventus','CB/LB','LCB','MEDIUM-HIGH','0000012100351003X21022200',31.0,38.89999999999999858,6,7.080000000000000071,'cb_bpd','Build-Up','cb_bpd','Aggressive',0.910000000000000031,'왼발 센터백 겸 레프트백 — 밍스 노쇠화의 프리미어리그 검증된 대체자로 부상. 세리에A 최근 6경기(45분+) 실측: cb_bpd/Aggressive와 0.91 유사도로 빌드업형 CB 성향 확인, 파우 토레스와 유사한 프로필. 유벤투스 희망가 €35m, 실제 협상가는 €30m선 추정. 노팅엄 포레스트·뉴캐슬도 관심. [2026-07-15 재확인] Matteo Moretto(로마노 채널): "협상 공식 개시" 확인, 밀란 €20m 대 빌라 €10-12m 간극. 에메리-비야레알 인연 배경.','https://readastonvilla.com/2026/06/15/aston-villa-in-lloyd-kelly-race-transfer-juventus-2026/; https://www.getfootballnewsitaly.com/2026/juventus-lloyd-kelly-leeds-united-and-aston-villa-interested-in-defender/','MEDIUM-HIGH — [2026-07-14 재확인] 리즈·에버턴과 3파전, 유벤투스 요구액 €35m→€30m로 하락. 빌라 CL 카드가 여전히 우위 요인이나 상단(72번 트래포드 참조) CL 진출 자체 불투명성 리스크 공통 적용. 등급 유지. / 2026-07-15 재확인: Moretto 협상 공식 개시 확인, 등급 유지.','켈리');
