INSERT INTO transfer_targets VALUES(58,'2026-summer','Eljif Elmas','엘리프 엘마스',838232,'RB Leipzig','M','CAM','HIGH','20123X5348656331322211110',47.60000000000000142,56.89999999999999858,6,6.599999999999999645,'cam_halfwinger','Roaming','cam_halfwinger','Balanced',0.8289999999999999592,'MEDIUM-HIGH — readastonvilla(2티어급) "가장 매력적인 선택지" + goonerdaily/caughtoffside 등 다수 매체 수렴: 페네르바흐체 제안 거절하고 빌라 선호 명확, CL 진출이 유인. RB라이프치히 buy option(€17m) 미행사로 이적 가능. 히트맵 MEDIUM-HIGH(나폴리 임대+국대 혼합 6경기). [2026-07-15 재확인] 프론트러너 지위 유지, 본인 빌라行 선호(페네르바흐체 거절) 재확인. RB라이프치히는 방출 의사, 협상 개시 준비 단계.','https://readastonvilla.com/2026/06/05/aston-villa-transfer-eljif-elmas-rb-leipzig-2026/; https://goonerdaily.com/2026/06/06/aston-villa-lead-race-to-sign-eljif-elmas-after-midfielder-makes-premier-league-preference-clear/','HIGH — [2026-07-14 재확인] 선수 본인이 페네르바흐체 매력적 제안 거절하고 빌라를 명확히 선호한다는 보도(Tuttomercatoweb), 빌라가 "가장 매력적인 옵션"으로 이적 레이스 주도. 가격도 €17m로 저렴. MEDIUM-HIGH에서 상향. / 2026-07-15 재확인: 프론트러너 지위·본인 선호 재확인, 등급 유지.','엘마스');
INSERT INTO transfer_targets VALUES(60,'2026-summer','Álex Remiro','알렉스 레미로',791773,'Real Sociedad','G','GK','MEDIUM-HIGH','0000000000000000010001X10',49.79999999999999716,10.80000000000000072,6,6.820000000000000284,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.960999999999999966,'MEDIUM-HIGH — TeamTalk(2티어) "더블딜 가속화" 확인: 마르티네스 유벤투스 이적 임박에 맞춰 신규 GK 영입 후보로 부상, 크리스탈 팰리스·뉴캐슬·바르셀로나와 경쟁. 바이아웃 €50m→€12m로 급락. 히트맵 HIGH(라리가 단일클럽 6경기). [2026-07-15 재확인] Mundo Deportivo: 레미로가 경쟁 선두, 바이아웃 €50m→€12m로 급락. 소시에다드는 재계약 종용 중이나 빌라 공식 접촉은 아직.','https://www.teamtalk.com/aston-villa/double-deal-accelerates-serhou-guirassy-signing-boost-alex-remiro-new-keeper-target; https://thehardtackle.com/transfer-news/2026/06/18/aston-villa-ahead-of-crystal-palace-newcastle-united-barcelona-in-alex-remiro-race/','MEDIUM-HIGH — [2026-07-14 재확인] 바이아웃이 €50m→€12m로 급락(빌라·뉴캐슬 모두 감당 가능). 다만 바르사·인테르도 컨택 중이고 선수 본인은 월드컵 스페인 대표팀 발탁 여부부터 기다리는 중이라 시점 불확실. 등급 유지. / 2026-07-15 재확인: 바이아웃 €12m 재확인, 소시에다드 재계약 종용 중, 공식 접촉은 아직.','레미로');
INSERT INTO transfer_targets VALUES(61,'2026-summer','Jarrod Bowen',NULL,NULL,'West Ham United','RW','RM','MEDIUM-HIGH',NULL,NULL,NULL,NULL,NULL,'wm_widemid','Support','wm_wideplm','Attack',0.8800000000000000044,'에머리가 다재다능성·주력·골 위협 높이 평가, 빌라 자산 매각 필요한 재정구조상 협상 미착수(웨스트햄 요구 £50m+) [2026-07-15 재확인] The Guardian(2티어): 첼시·에버턴과 경쟁 확인. £50m 요구가 여전히 부담, 웨스트햄 킷 캠페인으로 잔류 신호도 병존.','The Athletic(Jacob Tanswell) via search-cross-check; teamtalk.com/aston-villa/jarrod-bowen-transfer-news (2티어 보조) (수집 2026-07-10)','MEDIUM-HIGH — [2026-07-14 재확인] "빌라가 레이스 선두"(TeamTalk)이나 공식 오퍼는 아직 없음, £50m 가격표가 "선수 나이 대비 과함"이라는 빌라 내부 판단 보도. 첼시·에버턴·리버풀·뉴캐슬 등 다자 경쟁 지속. 등급 유지. / 2026-07-15 재확인: The Guardian(2티어) 첼시·에버턴 경쟁 확인, £50m 부담 지속.','보웬');
INSERT INTO transfer_targets VALUES(65,'2026-summer','Robin Risser','리세르',1387161,'RC Lens','GK','GK','HIGH','0000000000000000001001X30',52.70000000000000284,10.19999999999999928,6,6.633000000000000007,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.977999999999999981,'리그1 최근 6경기(45분+, 전경기 90분) 히트맵 240pt, 센트로이드 tool(52.7,10.2) — 중앙·자기골 근접, 전형적 라인 지키는 정통파. gk 커널 적합 gk_goalkeeper/Defend 0.978로 매우 높음(마르티네스 후속 대체자군과 동일 패턴). [2026-07-15 재확인] Athletic Tanswell(1티어): 레스테스가 여전히 1순위, 리세는 대안. 공식 오퍼 준비 단계.','https://www.transferfeed.com/clubs/aston-villa/15(2026-07-11); L''Équipe(Loïc Tanzi) "preparing opening offer" 보도(2026-07-11 검색); SofaScore API player/1387161 (2026-07-11 수집)','HIGH — [2026-07-14 재확인] L''Équipe 경유 복수 매체가 "빌라 오프닝 오퍼 준비 단계" 보도, 스즈키 기사에서도 "빌라 1옵션은 리세르, 스즈키는 대안"으로 확인. 랑스 2030계약이라 매각 저항 여전하나 우선순위 명확화로 MEDIUM-HIGH에서 상향. 실측 HIGH. / 2026-07-15 재확인: Athletic Tanswell(1티어) 1옵션 확인, 등급 유지.','리세르');
INSERT INTO transfer_targets VALUES(71,'2026-summer','Pedro Gonçalves','페드루 곤살베스',895764,'Sporting CP','AM','CAM','HIGH','542225X641431202122111100',37.39999999999999858,65.20000000000000284,6,6.879999999999999894,'cam_playmaker','Roaming','cam_playmaker','Roaming',0.7419999999999999929,'스포르팅·본인 모두 여름 이적 의사 확정(A Bola), 가격 €30m→€20-25m로 하향, 리버풀과 경쟁. 실측 결과 측면(RM)보다 중앙 공격형 미드필더(CAM) 적합도가 훨씬 높음(0.74 vs 0.23). 이벤트 스탯(같은 6경기 통합): 키패스 16(2.67/경기)·빅찬스 창출 2·xA 1.17(5경기 리포트분)·도움 2 — 창출력 우수. 반면 슛 16·유효슈팅 5·xG 0.61·득점 0 — 최근 표본에서 마무리는 xG 대비 부진. LM/LW 커널 재비교(0.702/0.667)도 CAM보다 낮아 실측·산출 모두 로저스형 박스크래셔가 아닌 중앙 크리에이터로 수렴. 슛맵(같은 6경기, 16슛): 박스 내 10/16(62.5%)·6야드 1개·헤더 0 — 헤더 전무는 박스크래셔/타겟형이 아님을 재확인. 평균 슈팅거리 15.8(골라인 기준, 박스 경계 부근)·평균 y 43.8(중앙 편향) — 중거리~박스 언저리에서 발로 마무리하는 전형적 중앙 크리에이터형 슈팅 패턴. [2026-07-15 재확인] A Bola: 스포르팅이 요구가 €40m→€20-25m로 급락, 조르지 멘드스가 직접 이적 추진. 리버풀도 경쟁.','https://readastonvilla.com/2026/06/12/aston-villa-transfer-news-pedro-goncalves-sporting-sale-2026/ ; https://footballplace.co.uk/aston-villa-pedro-goncalves-transfer-price-drop/ ; SofaScore API player 895764 (2026-07-12)','HIGH — [2026-07-14 재확인] 스포르팅이 €80m 바이아웃 대신 €20-25m까지 가격 대폭 인하, "완전히 매각 오픈" 상태 확인(A Bola). 빌라 CL 진출이 스포르팅이 원하는 "이적 프로필"에 부합. 리버풀·사우디 경쟁 존재하나 가격 장벽 해소로 MEDIUM-HIGH에서 상향. / 2026-07-15 재확인: 스포르팅 요구가 €40m→€20-25m 급락 확인, 등급 유지.','곤살베스');
INSERT INTO transfer_targets VALUES(75,'2026-summer','Pervis Estupiñán','에스투피냔',805465,'AC Milan','LB','LB','HIGH','21000X3100610007200032100',16.10000000000000143,49.10000000000000142,6,6.870000000000000106,'fb_att_wb','Support','fb_att_wb','Support',0.945999999999999953,'좌측면 전 깊이 커버 공격형 레프트백. 실측 6경기(세리에A, 322pt) 중심 tool(16,49). 커널 fit fb_att_wb/Support 0.946 (2위 fb_inverted/Build-Up 0.89). 밀란 아모림 구상 외, 호가 ~€14m. [2026-07-14 야간 재확인] Romano: "AVFC 좌측백 3인 숏리스트 중 상위, 딜 진행중, 협상 계속"(YouTube) — 단 조건 미확정, 데포르티보 라코루냐 경쟁 참전. 디뉴 대체가 아니라 마첸 백업/뎁스 역할로 영입(주전 보장 아님). [2026-07-15 재확인] Matteo Moretto(로마노 채널, 준1티어급): "협상 공식 개시" 확인 — 밀란-빌라 간 클럽 대 클럽 협상 단계 진입. 이적료 격차(€18-20m vs €10-12m)만 남음. 협상 단계 확인으로 HIGH 상향.','Moretto via SempreMilan https://sempremilan.com/moretto-aston-villa-enquire-milan-estupinan ; SofaScore player/805465 (6 Serie A ~2026-05-10)','MEASURED: 6 Serie A 45min+ 히트맵(322pt), fit 0.946. LINK: MEDIUM-HIGH (Moretto 1티어 문의/접촉, 서면오퍼 없음). [갱신] Romano(1티어) "deal is on, talks ongoing"로 진행 확인되나 아직 합의 단계 아님 — MEDIUM-HIGH 유지. / 2026-07-15: 협상 단계 진입(Moretto) 확인 — HIGH로 상향.','에스투피냔');
INSERT INTO transfer_targets VALUES(76,'2026-summer','Antonio Nusa','누사',1121923,'RB Leipzig','LW','LM','MEDIUM-HIGH','13010X6210443002220010000',25.89999999999999858,58.70000000000000284,6,7.25,'wm_wideplm','Attack','wm_wideplm','Attack',0.8810000000000000053,'높고 넓은 좌측 윙어(하프스페이스 인사이드 드리프트). 실측 6경기(분데스리가, 257pt) 중심 tool(26,59). 커널 fit wm_wideplm/Attack 0.881 (2위 wm_insidefwd/Balanced 0.845). 라이프치히 호가 £43~50m, PL 5개팀 경쟁. MEDIUM-LOW에서 상향. [2026-07-15 재확인] Football Insider(2티어): 라이프치히 £50m면 매각 의향 확인, 뉴캐슬 등 경쟁 심화, 재정 부담 우려 지속.','Football Insider/TEAMtalk/ESPN 관심 보도; SofaScore player/1121923 (6 Bundesliga ~2026-05-16)','MEDIUM-HIGH — [2026-07-14 재확인] 라이프치히 호가 £50m(€50-60m)로 확정, 2029계약이라 "매각 압박 없음"(no immediate pressure to sell) 명시. 경쟁 7클럽으로 확대(뉴캐슬·아스날·토트넘·밀란·아틀레티코·크팰). 빌라 자체 재정 여건상 "£50m는 부담될 수 있다"는 반증 보도 등장 — 등급 MEDIUM-HIGH 유지하되 실현성 리스크 상향 병기. / 2026-07-15 재확인: Football Insider(2티어) £50m 매각 의향 확인, 재정 부담 우려 지속.','누사');
INSERT INTO transfer_targets VALUES(77,'2026-summer','Johan Manzambi','만잠비',1518931,'SC Freiburg','CM','LDM','CONFIRMED','33414775548X6447877220320',43.60000000000000142,51.79999999999999716,6,7.620000000000000106,'dm_dlp','Roaming','dm_dlp','Roaming',0.8120000000000000551,'완전 box-to-box, 중앙 전역 커버(온아나 대체). 실측 6경기(분데스리가, 363pt) 중심 tool(44,52). 커널 fit LDM dm_dlp/Roaming 0.812 (RDM는 0.544로 약함 → 좌중앙 성향, LDM 전용). 평균 7.62 최상. [2026-07-14 확정] 빌라 합류 확정(사용자 확인). [2026-07-15 재확인] Romano "here we go": €60m+ 구두합의, 개인조건 완료. 뉴캐슬 £49m 구두합의를 히잭. 아직 공식 발표(메디컬) 전 단계.','Romano/Ornstein/Sky Germany 하이잭 보도(€70m 합의 임박); SofaScore player/1518931 (6 Bundesliga ~2026-05-16)','CONFIRMED — 합류 확정. 실측 신뢰 HIGH(6경기 전부 45분+, 363pt, fit 0.812). / 2026-07-15: 구단간·개인 합의 완료, 공식 발표만 대기 — CONFIRMED 유지.','만잠비');
INSERT INTO transfer_targets VALUES(82,'2026-summer','Archie Gray',NULL,1142335,'Tottenham Hotspur','MF','RDM','MEDIUM-HIGH','2022242467255X52657421432',56.52000000000000312,48.25,6,6.650000000000000355,'dm_dlp','Roaming','dm_dlp','Roaming',0.7970000000000000417,'PL/UCL 최근 6경기(45분+, U21 국가대표 경기 제외) 히트맵 299pt, 중앙 우측 편향(tool 56.5/48.3) — RDM 배치시 dm_dlp/Roaming 0.797, LDM 배치시 0.528로 하락해 우측 적합 확인. [2026-07-15 재확인] 도르트문트·맨유·첼시 포함 다자 경쟁 지속, 빌라 "확정 관심" 보도(경쟁사 다수).','teamtalk.com; footballfancast.com; spurs-web.com; SofaScore API player 1142335 (수집 2026-07-13)','MEDIUM-HIGH — [2026-07-14 재확인] 기존 "스퍼스 강등시에만 현실화" 전제가 무효화됨 — 스퍼스 잔류에도 도르트문트·맨유·첼시·빌라 4파전이 강등 여부와 무관하게 진행 중으로 확인. 공식 오퍼는 아직 없음. 등급 유지(재검증 근거 갱신). / 2026-07-15 재확인: 4파전 경쟁 지속(도르트문트·맨유·첼시), 등급 유지.','그레이');
INSERT INTO transfer_targets VALUES(85,'2026-summer','Martin Baturina','마르틴 바투리나',1090019,'Como','AM','CAM','MEDIUM-HIGH','31114757647X7526531211111',42.82000000000000028,57.32000000000000028,6,7.25,'cam_playmaker','Balanced','cam_playmaker','Build-Up',0.6550000000000000266,'빌라 영입팀이 €50-55m 공식 오퍼 제출, 코모측 €80m 요구로 거절(2030계약 장기 보유); 바이에른도 경쟁. tier-1(로마노/오른스틴/스카이) 미확인, FootballInsider247·TheHardTackle·GiveMeSport(2티어급) 복수가 오퍼·거절 단계까지 수렴해 MEDIUM-HIGH. 실측: Serie A 최근 6경기(45분+, 컵 1경기 포함) 431 히트포인트, cam_playmaker/Build-Up 적합 0.655(중간) — 중앙 공격형 미드필더로 창조적 플레이메이커 성향과 부합. [2026-07-15 재확인] 빌라가 €50-55m 실제 오퍼 제출 확인(Sport Witness/Sky Italia 경유), 코모가 거절하며 €80m 요구. 맨유·바이에른·토트넘도 경쟁. 실제 오퍼 제출·거절이라는 협상 단계 행위 확인 — MEDIUM-HIGH로 상향.','https://www.footballinsider247.com/aston-villa/martin-baturina-everything-you-need-to-know-about-69m-rated-aston-villa-target-as-bid-submitted ; https://thehardtackle.com/transfer-news/2026/07/07/aston-villa-tottenham-told-to-pay-e80-million-to-sign-martin-baturina/ ; https://www.givemesport.com/aston-villa-martin-baturina-transfer-bid-emery/ (2026-07-14 evening watch)','MEDIUM — [2026-07-14 재확인] 빌라의 €50-55m 공식 오퍼가 코모에 거절당함, 코모는 €80m 요구하며 "매각 불가(non-transferable)" 입장. The Athletic(1티어, Tanswell)은 빌라 SCR상 선수 1명에 £40m 이상 못 쓴다고 명시 — 코모 요구액과 격차가 2배 가까이 벌어져 현실성 하향. MEDIUM-HIGH에서 하향. / 2026-07-15: 실제 오퍼 제출·거절 확인(협상 단계)로 상향.','바투리나');
INSERT INTO transfer_targets VALUES(88,'2026-summer','Matías Soulé','마티아스 소울레',1082406,'AS Roma','FW','RM','MEDIUM-HIGH','101131114X011331012100001',72.3299999999999983,61.42999999999999972,6,6.919999999999999929,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.9050000000000000266,'로마 FFP 압박(€60m 자본이득 필요)으로 매각 후보, 본인은 프리미어리그·빌라 이적 희망(가제타 델로 스포르트). 왓킨스 다음 레벨을 위한 연계형 우측 자원. 실측: Serie A 최근 6경기(45분+, 2026-04~05, 336pt) 우측 강한 편향(tool_x 72.3), wm_insidefwd/Balanced 0.905 — RM 후보 중 최고 수준. [2026-07-15 재확인] 협상 진행 중이나 공식 오퍼 아직 없음, €40m부터 협상 개시 필요. 로마는 그린우드 자금 마련 위해 매각 필요성 증가.','footballinsider247.com; gazzetta.it(via Sport Witness); readastonvilla.com; thehardtackle.com; SofaScore API player 1082406 (수집 2026-07-14)','MEDIUM-HIGH — [2026-07-14 재확인] 로마 6/30 FFP 데드라인은 지났으나 여전히 매각 후보로 거론, 도르트문트가 "serious" 경쟁자로 남음. 빌라·본머스는 아직 "물밑 타진" 수준. 등급 유지. / 2026-07-15 재확인: 협상 진행 중이나 공식 오퍼 아직 없음, 등급 유지.','소울레');
INSERT INTO transfer_targets VALUES(89,'2026-summer','Lucas Bergvall','루카스 베르그발',NULL,'Tottenham Hotspur','CM/AM','CAM','MEDIUM-HIGH',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'티엘레만스 맨유 이적(바이아웃 발동, CONFIRMED)으로 생긴 중원 공백 대체 후보. Football Insider(2티어): 첼시와 함께 "open race", 1월에도 접촉했으나 거절당함. 본인이 스퍼스에 이적 희망 의사 전달(구단 공식 컨택은 아직 없음). [2026-07-15 재확인] David Ornstein(Athletic, 1티어): 스퍼스가 빌라의 과거 오퍼를 즉각 거절했음을 확인 — 즉, 실제 접촉·오퍼가 있었음을 1티어가 실증. 다만 Sky Sports Michael Bridge(1티어)는 "이번 여름 잔류 통보"로 상충. 실제 이적 시도는 확인됐으나 성사 불투명 — MEDIUM-HIGH로 상향.','Football Insider(via football365, 2026-07-14) — "open race" 보도; TeamTalk/readastonvilla — 티엘레만스·와튼 대안으로 거론; 상충: Sky Sports 기자 Michael Bridge(1티어) — "이번 여름 잔류 통보받음" 보도','MEDIUM — PENDING MEASUREMENT(Chrome 미연결로 SofaScore 히트맵 미수집). 2티어 복수 관심 보도이나 1티어(Sky Sports Michael Bridge)가 잔류 보도로 상충 — 협상 단계 아님, 슬롯(CAM)은 잠정 배치. / 2026-07-15: 1티어(Ornstein) 과거 오퍼·거절 확인으로 상향, 단 1티어(Bridge) 잔류 보도와 상충 지속.','베르그발');
